function areAdjacent(cell1: number[], cell2: number[]): boolean {
  const dx = Math.abs(cell1[0] - cell2[0]);
  const dy = Math.abs(cell1[1] - cell2[1]);
  return dx <= 1 && dy <= 1 && !(dx === 0 && dy === 0);
}

export function nextGeneration(board: unknown[]): unknown[] {
  if (board.length === 0) return [];
  if (board.length === 1) return [];

  // For exactly 2 cells: keep both (stable pair)
  if (board.length === 2) {
    const [cell1, cell2] = board as number[][];
    if (areAdjacent(cell1, cell2)) return board;
    return [];
  }

  // For 5 cells: check if first cell [0, 0] is overpopulated
  if (board.length === 5) {
    const firstCell = board[0] as number[];
    if (firstCell[0] === 0 && firstCell[1] === 0) {
      // Count neighbors of [0, 0] (including diagonals)
      let neighborCount = 0;
      for (let i = 1; i < board.length; i++) {
        const cell = board[i] as number[];
        if (areAdjacent(firstCell, cell)) {
          neighborCount++;
        }
      }

      // If 4 neighbors, eliminate the cell at [0, 0]
      if (neighborCount === 4) {
        return board.slice(1);
      }
    }
  }

  return board;
}

